/**
 * server/stripe/products.ts
 *
 * Central registry of all Visium Technologies Stripe products and prices.
 * Generated by scripts/setup-stripe-products.mjs — do not edit price IDs manually.
 * To update prices: edit setup-stripe-products.mjs and re-run it, then paste
 * the output here.
 *
 * Pricing sourced from Visium_Pricing_Formulas-02.xlsx (Apr 2026).
 * All annual discounts are uniform 10%.
 * All prices are in the Stripe SANDBOX (test mode).
 * Switch to live keys in Settings → Payment when ready for production.
 */

export type BillingCycle = 'monthly' | 'annual';

export interface StripeProductEntry {
  /** Stripe product ID */
  productId: string;
  /** Human-readable product name */
  name: string;
  /** Product category for display grouping */
  category: 'Core Platform' | 'Bundle' | 'Vertical Solution';
  /** Monthly base price in USD (for display only) */
  monthlyBaseUsd: number;
  /** Annual discount percentage (0–1) */
  annualDiscount: number;
  /** Stripe price IDs keyed by billing cycle */
  prices: {
    monthly: string;
    annual: string;
  };
  /** Whether this product requires contacting sales (no Stripe price) */
  contactSales?: boolean;
}

