/**
 * Get the Stripe price ID for a given product and billing cycle.
 * Returns null if the product requires contacting sales.
 */
export function getStripePrice(
  productId: string,
  billingCycle: BillingCycle
): string | null {
  const product = VISIUM_PRODUCTS[productId];
  if (!product) return null;
  if (product.contactSales) return null;
  const priceId = product.prices[billingCycle];
  return priceId === 'contact_sales' ? null : priceId;
}

/**
 * Get a human-readable list of all products for a given category.
 */
export function getProductsByCategory(category: StripeProductEntry['category']) {
  return Object.entries(VISIUM_PRODUCTS)
    .filter(([, p]) => p.category === category)
    .map(([id, p]) => ({ id, ...p }));
}
